INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'init-setup',
  'Lab Bootstrap',
  'Execution policy, firewall basics, lab directory tree (C:\Lab / LabApps / LabShare), ICMP allow, high-perf power plan, student + svcbackup accounts. Foundation for every other script.',
  'Initial Setup',
  'windows',
  'beginner',
  $INIT_SETUP$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# --- Execution policy (so dependent scripts run without prompts) ---
Write-Step "Setting execution policy to Bypass for CurrentUser and LocalMachine"
Set-ExecutionPolicy -Scope LocalMachine -ExecutionPolicy Bypass -Force -ErrorAction SilentlyContinue
Set-ExecutionPolicy -Scope CurrentUser  -ExecutionPolicy Bypass -Force -ErrorAction SilentlyContinue

# --- Lab directory tree used by other scripts ---
Write-Step "Creating C:\Lab working directories"
foreach ($dir in @("C:\Lab","C:\Lab\logs","C:\Lab\artifacts","C:\Lab\tools","C:\Lab\loot","C:\LabApps","C:\LabShare")) {
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
}

# --- Set network profile to Private (lets SMB/WinRM/RDP firewall rules apply) ---
Write-Step "Setting all network profiles to Private"
Get-NetConnectionProfile -ErrorAction SilentlyContinue | ForEach-Object {
    if ($_.NetworkCategory -ne "Private") {
        Set-NetConnectionProfile -InterfaceIndex $_.InterfaceIndex -NetworkCategory Private -ErrorAction SilentlyContinue
    }
}

# --- Allow ICMP echo (ping) so students can enumerate ---
Write-Step "Enabling ICMPv4 echo-request in firewall"
Get-NetFirewallRule -Name "FPS-ICMP4-ERQ-In" -ErrorAction SilentlyContinue | Enable-NetFirewallRule -ErrorAction SilentlyContinue
New-NetFirewallRule -DisplayName "Lab-ICMP-Allow-In" -Direction Inbound -Protocol ICMPv4 -IcmpType 8 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

# --- High-performance power plan (keeps VMs responsive for live demos) ---
Write-Step "Switching to High Performance power plan"
try { powercfg -setactive SCHEME_MIN 2>$null } catch {}

# --- Stamp a lab marker so students can find the environment build info ---
Write-Step "Writing C:\Lab\lab-info.txt"
$info = @"
Lab Environment
---------------
Built       : $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')
Hostname    : $env:COMPUTERNAME
OS Version  : $((Get-CimInstance Win32_OperatingSystem).Caption)
Arch        : $env:PROCESSOR_ARCHITECTURE
Admin User  : Administrator
Contact     : support@internal.lab
"@
Set-Content "C:\Lab\lab-info.txt" $info -Encoding UTF8

# --- Create a dedicated non-privileged student account used across lab scripts ---
Write-Step "Ensuring student accounts exist"
$pw = ConvertTo-SecureString "LabStudent!" -AsPlainText -Force
$accounts = @(
    @{ Name = "student";  FullName = "Lab Student";     Group = "Users" },
    @{ Name = "svcbackup"; FullName = "Backup Service"; Group = "Backup Operators" }
)
foreach ($acct in $accounts) {
    $existing = Get-LocalUser -Name $acct.Name -ErrorAction SilentlyContinue
    if (-not $existing) {
        New-LocalUser -Name $acct.Name -Password $pw -FullName $acct.FullName -Description "Lab account" -PasswordNeverExpires -UserMayNotChangePassword -ErrorAction SilentlyContinue | Out-Null
        Add-LocalGroupMember -Group $acct.Group -Member $acct.Name -ErrorAction SilentlyContinue
    }
}

Write-Host ""
Write-Host "=== init-setup complete ==="
Write-Host "Lab tree : C:\Lab, C:\LabApps, C:\LabShare"
Write-Host "Accounts : student / svcbackup (password LabStudent!)"
Write-Host "ICMP     : allowed"
$INIT_SETUP$,
  '[]'::jsonb,
  '{}',
  20,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'smb-baseline',
  'SMB (Standard-Secure)',
  'Public + Users shares with authenticated-only access, SMB signing required, SMB1 disabled, null sessions blocked. Clean baseline for real-client synthesis.',
  'Network Services',
  'windows',
  'beginner',
  $SMB_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline SMB: enable file sharing with authenticated-only access.
# NO null session, NO anonymous enumeration, NO guest access.
# Use smb-config.ps1 if you want the vulnerable variant.

$BasePath = "C:\LabShare"

Write-Step "Setting network profile to Private"
Get-NetConnectionProfile -ErrorAction SilentlyContinue | ForEach-Object {
    if ($_.NetworkCategory -ne "Private") {
        Set-NetConnectionProfile -InterfaceIndex $_.InterfaceIndex -NetworkCategory Private -ErrorAction SilentlyContinue
    }
}

Write-Step "Enabling File and Printer Sharing firewall rules"
Enable-NetFirewallRule -DisplayGroup "File and Printer Sharing" -ErrorAction SilentlyContinue | Out-Null

Write-Step "Creating share folders"
foreach ($folder in @($BasePath, "$BasePath\Public", "$BasePath\Users")) {
    if (-not (Test-Path $folder)) { New-Item -ItemType Directory -Path $folder -Force | Out-Null }
}

Write-Step "Setting NTFS permissions (authenticated users only)"
icacls "$BasePath\Public" /inheritance:r /grant:r "Authenticated Users:(OI)(CI)RX" "Administrators:(OI)(CI)F" | Out-Null
icacls "$BasePath\Users"  /inheritance:r /grant:r "Users:(OI)(CI)M"                "Administrators:(OI)(CI)F" | Out-Null

Write-Step "Creating SMB shares"
foreach ($name in @("Public","Users")) {
    $existing = Get-SmbShare -Name $name -ErrorAction SilentlyContinue
    if ($existing) { Remove-SmbShare -Name $name -Force -ErrorAction SilentlyContinue }
}
New-SmbShare -Name "Public" -Path "$BasePath\Public" -ReadAccess  "Authenticated Users" -FullAccess "Administrators" -ErrorAction SilentlyContinue | Out-Null
New-SmbShare -Name "Users"  -Path "$BasePath\Users"  -ChangeAccess "Users"               -FullAccess "Administrators" -ErrorAction SilentlyContinue | Out-Null

Write-Step "Enforcing secure SMB settings (signing required, no null session)"
# Server-side: require signing, deny null sessions
Set-SmbServerConfiguration -RequireSecuritySignature $true -EnableSecuritySignature $true -Confirm:$false -ErrorAction SilentlyContinue
Set-ItemProperty -Path "HKLM:\SYSTEM\CurrentControlSet\Services\LanmanServer\Parameters" -Name "RestrictNullSessAccess" -Value 1 -Type DWord -Force
Set-ItemProperty -Path "HKLM:\SYSTEM\CurrentControlSet\Control\Lsa"                      -Name "RestrictAnonymous"     -Value 1 -Type DWord -Force

# Disable SMBv1 entirely (current best practice)
Set-SmbServerConfiguration -EnableSMB1Protocol $false -Confirm:$false -ErrorAction SilentlyContinue

Write-Step "Seeding a small amount of realistic content"
Set-Content "$BasePath\Public\README.txt" @"
Public share. Read-only for authenticated users.
For team files, use the Users share.
"@ -Encoding UTF8

Write-Host ""
Write-Host "=== smb-baseline complete ==="
Write-Host "Shares    : Public (auth read), Users (auth RW)"
Write-Host "SMB1      : disabled"
Write-Host "Signing   : required"
Write-Host "Null sess : blocked"
$SMB_BASELINE$,
  '["445/SMB"]'::jsonb,
  '{"init-setup"}',
  20,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'rdp-baseline',
  'RDP (Standard-Secure)',
  'RDP on 3389 with NLA required, TLS security layer, high encryption. Only the student account granted access.',
  'Network Services',
  'windows',
  'beginner',
  $RDP_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline RDP: enable with NLA + TLS, grant specific users only.
# Use rdp-config.ps1 for the NLA-off / low-security-layer variant.

Write-Step "Enabling Remote Desktop"
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server" -Name "fDenyTSConnections" -Value 0 -Force

Write-Step "Requiring Network Level Authentication"
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "UserAuthentication" -Value 1 -Force
# SecurityLayer = 2 means SSL (TLS 1.0) required
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "SecurityLayer"     -Value 2 -Force
# MinEncryptionLevel = 3 means High encryption required (128-bit)
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "MinEncryptionLevel" -Value 3 -Force

Write-Step "Enabling Remote Desktop firewall group"
Enable-NetFirewallRule -DisplayGroup "Remote Desktop" -ErrorAction SilentlyContinue | Out-Null

Write-Step "Granting RDP access to student (only)"
try { Add-LocalGroupMember -Group "Remote Desktop Users" -Member "student" -ErrorAction SilentlyContinue } catch {}

Write-Step "Starting Remote Desktop Services"
Set-Service -Name TermService -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name TermService -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== rdp-baseline complete ==="
Write-Host "Port 3389     : open"
Write-Host "NLA           : required"
Write-Host "Security      : TLS + high encryption"
Write-Host "RDP users     : student"
$RDP_BASELINE$,
  '["3389/RDP"]'::jsonb,
  '{"init-setup"}',
  10,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
