  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'ssh-baseline',
  'OpenSSH (Standard)',
  'Installs OpenSSH Server Windows capability, starts sshd + ssh-agent with stock config, opens port 22. No seeded keys or relaxed auth.',
  'Network Services',
  'windows',
  'beginner',
  $SSH_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline OpenSSH: install + start sshd with stock sshd_config.
# No seeded keys, no relaxed auth. Use ssh-config.ps1 for the artifact-rich variant.

Write-Step "Installing OpenSSH Server Windows capability"
try {
    $cap = Get-WindowsCapability -Online -Name "OpenSSH.Server*" -ErrorAction SilentlyContinue
    if ($cap -and $cap.State -ne 'Installed') {
        Add-WindowsCapability -Online -Name $cap.Name -ErrorAction SilentlyContinue | Out-Null
    }
} catch { Write-Host "OpenSSH capability install: $($_.Exception.Message)" }

Write-Step "Starting sshd service"
Set-Service -Name sshd -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name sshd -ErrorAction SilentlyContinue

# Also start the agent so pubkey workflows work if admin uses them later
Set-Service -Name 'ssh-agent' -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name 'ssh-agent' -ErrorAction SilentlyContinue

Write-Step "Opening TCP/22 in firewall"
Get-NetFirewallRule -Name "OpenSSH-Server-In-TCP" -ErrorAction SilentlyContinue | Enable-NetFirewallRule -ErrorAction SilentlyContinue
New-NetFirewallRule -DisplayName "Lab-SSH-22-Allow" -Direction Inbound -Protocol TCP -LocalPort 22 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

# Use the shipped sshd_config defaults -- no permissive overrides here.
# (The OpenSSH-Server capability installs a sane default config.)

Write-Step "Ensuring default shell is PowerShell for SSH sessions"
try {
    $regPath = "HKLM:\SOFTWARE\OpenSSH"
    if (-not (Test-Path $regPath)) { New-Item -Path $regPath -Force | Out-Null }
    New-ItemProperty -Path $regPath -Name DefaultShell -PropertyType String -Value (Get-Command powershell.exe).Source -Force | Out-Null
} catch {}

Write-Host ""
Write-Host "=== ssh-baseline complete ==="
Write-Host "Service   : sshd + ssh-agent started (auto)"
Write-Host "Port      : 22/TCP"
Write-Host "Config    : stock (no relaxed auth)"
$SSH_BASELINE$,
  '["22/SSH"]'::jsonb,
  '{"init-setup"}',
  90,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'winrm-baseline',
  'WinRM HTTPS (Hardened)',
  'HTTPS listener on 5986 with self-signed cert, Kerberos + Negotiate auth only, Basic auth denied, unencrypted transport denied. Removes the default HTTP listener.',
  'Network Services',
  'windows',
  'intermediate',
  $WINRM_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline WinRM: HTTPS listener with self-signed cert, Kerberos/Negotiate only,
# no Basic auth, no unencrypted. Use winrm-http.ps1 for the unencrypted variant.

Write-Step "Starting WinRM service"
Set-Service -Name WinRM -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name WinRM -ErrorAction SilentlyContinue

Write-Step "Bootstrapping PSRemoting (SkipNetworkProfileCheck)"
Enable-PSRemoting -Force -SkipNetworkProfileCheck -ErrorAction SilentlyContinue | Out-Null

Write-Step "Creating self-signed certificate for HTTPS listener"
$cert = Get-ChildItem Cert:\LocalMachine\My | Where-Object { $_.Subject -eq "CN=$env:COMPUTERNAME" -and $_.EnhancedKeyUsageList.ObjectId -contains '1.3.6.1.5.5.7.3.1' } | Select-Object -First 1
if (-not $cert) {
    $cert = New-SelfSignedCertificate -DnsName $env:COMPUTERNAME -CertStoreLocation Cert:\LocalMachine\My -KeyExportPolicy Exportable -Provider "Microsoft Enhanced RSA and AES Cryptographic Provider" -ErrorAction SilentlyContinue
}

Write-Step "Configuring HTTPS listener on 5986"
if ($cert) {
    # Remove existing HTTPS listeners to avoid conflicts, then recreate
    & winrm delete winrm/config/Listener?Address=*+Transport=HTTPS 2>$null | Out-Null
    & winrm create winrm/config/Listener?Address=*+Transport=HTTPS "@{Hostname=`"$env:COMPUTERNAME`";CertificateThumbprint=`"$($cert.Thumbprint)`"}" 2>$null | Out-Null
}

# Delete the default HTTP listener created by Enable-PSRemoting
& winrm delete winrm/config/Listener?Address=*+Transport=HTTP 2>$null | Out-Null

Write-Step "Hardening auth: Kerberos/Negotiate only, no Basic, no unencrypted"
& winrm set winrm/config/service           '@{AllowUnencrypted="false"}' 2>$null | Out-Null
& winrm set winrm/config/service/auth      '@{Basic="false";Kerberos="true";Negotiate="true";CredSSP="false"}' 2>$null | Out-Null
& winrm set winrm/config/client            '@{AllowUnencrypted="false"}' 2>$null | Out-Null
& winrm set winrm/config/client/auth       '@{Basic="false";Kerberos="true";Negotiate="true"}' 2>$null | Out-Null

Write-Step "Opening TCP/5986 (HTTPS) in firewall; removing 5985 if present"
New-NetFirewallRule -DisplayName "Lab-WinRM-5986-Allow" -Direction Inbound -Protocol TCP -LocalPort 5986 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null
Get-NetFirewallRule -DisplayName "Lab-WinRM-5985-Allow" -ErrorAction SilentlyContinue | Remove-NetFirewallRule -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== winrm-baseline complete ==="
Write-Host "HTTPS listener : 5986/TCP (self-signed cert)"
Write-Host "HTTP listener  : removed"
Write-Host "Auth           : Kerberos + Negotiate (no Basic)"
Write-Host "Unencrypted    : denied"
$WINRM_BASELINE$,
  '["5986/WinRM-HTTPS"]'::jsonb,
  '{"init-setup"}',
  30,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
