INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'mssql-baseline',
  'MSSQL (Hardened)',
  'Configures an already-installed SQL Server instance for Windows-auth only, disables SA, disables xp_cmdshell, enables TCP on 1433, opens firewall. No-ops if no MSSQL service is present.',
  'Network Services',
  'windows',
  'intermediate',
  $MSSQL_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline MSSQL: if SQL Express is already installed, configure it safely --
# Windows-auth only, xp_cmdshell disabled, SA disabled, TCP on 1433 with
# standard firewall rule. Does NOT install SQL Server (that's a heavy download
# and belongs in a Proxmox template or separate install script).

$sqlService = Get-Service -Name 'MSSQL*' -ErrorAction SilentlyContinue |
              Where-Object { $_.Name -like 'MSSQL$*' -or $_.Name -eq 'MSSQLSERVER' } |
              Select-Object -First 1

if (-not $sqlService) {
    Write-Host "No MSSQL service detected on this host -- skipping SQL baseline."
    Write-Host "Install SQL Server Express first, then re-run this script."
    [Environment]::Exit(0)
}

Write-Step "Found SQL service: $($sqlService.Name)"
Set-Service -Name $sqlService.Name -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name $sqlService.Name -ErrorAction SilentlyContinue

# Instance short name for sqlcmd -S argument
$instanceName = if ($sqlService.Name -like 'MSSQL$*') { $sqlService.Name.Substring(6) } else { 'MSSQLSERVER' }
$sqlServerArg = if ($instanceName -eq 'MSSQLSERVER') { '.' } else { ".\$instanceName" }

Write-Step "Forcing Windows-authentication-only (LoginMode=1)"
$regBase = "HKLM:\SOFTWARE\Microsoft\Microsoft SQL Server"
$instances = Get-ChildItem $regBase -ErrorAction SilentlyContinue |
             Where-Object { $_.Name -match "MSSQL\d+\.$instanceName" }
foreach ($inst in $instances) {
    $serverPath = "$($inst.PSPath)\MSSQLServer"
    if (Test-Path $serverPath) {
        Set-ItemProperty -Path $serverPath -Name "LoginMode" -Value 1 -Force
    }
}

Write-Step "Enabling TCP/IP on port 1433 (standard)"
foreach ($inst in $instances) {
    $tcpPath = "$($inst.PSPath)\MSSQLServer\SuperSocketNetLib\Tcp"
    if (Test-Path $tcpPath) {
        Set-ItemProperty -Path $tcpPath -Name "Enabled" -Value 1 -Force
        $ipAllPath = "$tcpPath\IPAll"
        if (Test-Path $ipAllPath) {
            Set-ItemProperty -Path $ipAllPath -Name "TcpPort" -Value "1433" -Force
            Set-ItemProperty -Path $ipAllPath -Name "TcpDynamicPorts" -Value "" -Force
        }
    }
}

Restart-Service -Name $sqlService.Name -Force -ErrorAction SilentlyContinue
Start-Sleep -Seconds 8

# Find sqlcmd
$sqlcmd = $null
foreach ($pattern in @(
    "C:\Program Files\Microsoft SQL Server\Client SDK\ODBC\*\Tools\Binn\SQLCMD.EXE",
    "C:\Program Files\Microsoft SQL Server\*\Tools\Binn\SQLCMD.EXE"
)) {
    $found = Get-ChildItem -Path $pattern -ErrorAction SilentlyContinue | Select-Object -First 1
    if ($found) { $sqlcmd = $found.FullName; break }
}

if ($sqlcmd) {
    Write-Step "Disabling SA + xp_cmdshell"
    & $sqlcmd -S $sqlServerArg -E -Q "ALTER LOGIN [sa] DISABLE;" 2>&1 | Out-Null
    & $sqlcmd -S $sqlServerArg -E -Q @"
EXEC sp_configure 'show advanced options', 1; RECONFIGURE;
EXEC sp_configure 'xp_cmdshell', 0; RECONFIGURE;
EXEC sp_configure 'show advanced options', 0; RECONFIGURE;
"@ 2>&1 | Out-Null
} else {
    Write-Host "sqlcmd not found -- SA disable + xp_cmdshell lockdown skipped."
}

Write-Step "Opening TCP/1433 in firewall"
New-NetFirewallRule -DisplayName "Lab-MSSQL-1433-Allow" -Direction Inbound -Protocol TCP -LocalPort 1433 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

Write-Host ""
Write-Host "=== mssql-baseline complete ==="
Write-Host "Auth mode     : Windows-only"
Write-Host "SA account    : disabled"
Write-Host "xp_cmdshell   : disabled"
Write-Host "Port          : 1433/TCP"
$MSSQL_BASELINE$,
  '["1433/SQL"]'::jsonb,
  '{"init-setup"}',
  60,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'ftp-baseline',
  'IIS FTP (Authenticated, SSL)',
  'IIS FTP on port 21 with anonymous disabled, basic auth required, SSL enforced on control + data channels using a self-signed cert. Counterpart to ftp-anonymous.',
  'Network Services',
  'windows',
  'intermediate',
  $FTP_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline FTP: IIS FTP on port 21 with authentication required (NO anonymous),
# SSL policy set to require SSL for both control + data channels. Counterpart
# to ftp-anonymous (vulnerable).

Write-Step "Installing IIS + FTP features"
$isServer = (Get-CimInstance Win32_OperatingSystem).ProductType -ne 1
if ($isServer) {
    Install-WindowsFeature -Name Web-Server,Web-Ftp-Server,Web-Ftp-Service -IncludeManagementTools -ErrorAction SilentlyContinue | Out-Null
} else {
    Enable-WindowsOptionalFeature -Online -FeatureName IIS-WebServerRole,IIS-FTPServer,IIS-FTPSvc -All -NoRestart -ErrorAction SilentlyContinue | Out-Null
}

$ftpRoot = "C:\FTP\Shared"
Write-Step "Creating FTP root at $ftpRoot"
if (-not (Test-Path $ftpRoot)) { New-Item -Path $ftpRoot -ItemType Directory -Force | Out-Null }

Set-Content "$ftpRoot\README.txt" @"
Authenticated FTP share.
Contact IT for credentials. Anonymous access is not permitted.
"@ -Encoding ASCII

# Self-signed cert for FTPS
Write-Step "Creating self-signed cert for FTPS"
$cert = Get-ChildItem Cert:\LocalMachine\My |
        Where-Object { $_.Subject -eq "CN=$env:COMPUTERNAME-ftp" } |
        Select-Object -First 1
if (-not $cert) {
    $cert = New-SelfSignedCertificate -DnsName "$env:COMPUTERNAME-ftp" -CertStoreLocation Cert:\LocalMachine\My -KeyExportPolicy Exportable -ErrorAction SilentlyContinue
}

Import-Module WebAdministration -ErrorAction SilentlyContinue

$siteName = "LabFTP"
Write-Step "Configuring FTP site '$siteName' on port 21 (authenticated, SSL required)"
try {
    if (Get-WebSite -Name $siteName -ErrorAction SilentlyContinue) { Remove-WebSite -Name $siteName -ErrorAction SilentlyContinue }
    New-WebFtpSite -Name $siteName -Port 21 -PhysicalPath $ftpRoot -Force -ErrorAction SilentlyContinue | Out-Null

    # Authenticated only -- anonymous DISABLED
    Set-ItemProperty "IIS:\Sites\$siteName" -Name ftpServer.security.authentication.anonymousAuthentication.enabled -Value $false
    Set-ItemProperty "IIS:\Sites\$siteName" -Name ftpServer.security.authentication.basicAuthentication.enabled     -Value $true

    # Require SSL for both channels (policy=1 == SslRequire)
    Set-ItemProperty "IIS:\Sites\$siteName" -Name ftpServer.security.ssl.controlChannelPolicy -Value 1
    Set-ItemProperty "IIS:\Sites\$siteName" -Name ftpServer.security.ssl.dataChannelPolicy    -Value 1
    if ($cert) {
        Set-ItemProperty "IIS:\Sites\$siteName" -Name ftpServer.security.ssl.serverCertHash -Value $cert.Thumbprint
    }

    # Authorize domain users / local Users group for read; admins full
    Add-WebConfiguration "/system.ftpServer/security/authorization" -Value @{accessType="Allow";roles="Users";permissions=1} -PSPath IIS: -Location $siteName -ErrorAction SilentlyContinue
    Add-WebConfiguration "/system.ftpServer/security/authorization" -Value @{accessType="Allow";roles="Administrators";permissions=3} -PSPath IIS: -Location $siteName -ErrorAction SilentlyContinue
} catch {
    Write-Host "IIS FTP configuration failed: $($_.Exception.Message)"
}

Write-Step "Opening TCP/21 + passive range 40000-40100"
New-NetFirewallRule -DisplayName "Lab-FTP-21-Allow"      -Direction Inbound -Protocol TCP -LocalPort 21          -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null
New-NetFirewallRule -DisplayName "Lab-FTP-Passive-Allow" -Direction Inbound -Protocol TCP -LocalPort 40000-40100 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

Start-Service "FTPSVC" -ErrorAction SilentlyContinue
Set-Service   "FTPSVC" -StartupType Automatic -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== ftp-baseline complete ==="
Write-Host "Anonymous  : disabled"
Write-Host "Basic auth : required"
Write-Host "SSL        : required (self-signed cert)"
Write-Host "Port       : 21/TCP"
$FTP_BASELINE$,
  '["21/FTP"]'::jsonb,
  '{"init-setup"}',
  180,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'dns-baseline',
  'DNS Server (Forwarder)',
  'Windows Server-only: installs the DNS Server role, configures 1.1.1.1 + 8.8.8.8 forwarders with root hints, opens TCP+UDP 53. No-ops on client SKUs.',
  'Network Services',
  'windows',
  'beginner',
  $DNS_BASELINE$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# Baseline DNS: install DNS Server role, configure it to forward upstream,
# open TCP+UDP 53. Intended for a standalone Windows Server (DCs already
# bundle DNS via Install-ADDSForest; this baseline is for a plain DNS host).
# Works on Windows Server only -- DNS Server role is not available on client SKUs.

$isServer = (Get-CimInstance Win32_OperatingSystem).ProductType -ne 1
if (-not $isServer) {
    Write-Host "DNS Server role is Server-only -- this VM is a client SKU. Skipping."
    Write-Host "If you need DNS on a client, use a forwarder (hosts file / Unbound) instead."
    [Environment]::Exit(0)
}

Write-Step "Installing DNS Server role"
Install-WindowsFeature -Name DNS -IncludeManagementTools -ErrorAction SilentlyContinue | Out-Null

Write-Step "Configuring upstream forwarders (1.1.1.1, 8.8.8.8)"
try {
    Set-DnsServerForwarder -IPAddress "1.1.1.1","8.8.8.8" -UseRootHint $true -ErrorAction SilentlyContinue
} catch { Write-Host "Forwarder config failed: $($_.Exception.Message)" }

Write-Step "Opening TCP+UDP 53 in firewall"
New-NetFirewallRule -DisplayName "Lab-DNS-53-TCP-Allow" -Direction Inbound -Protocol TCP -LocalPort 53 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null
New-NetFirewallRule -DisplayName "Lab-DNS-53-UDP-Allow" -Direction Inbound -Protocol UDP -LocalPort 53 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

Set-Service -Name DNS -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name DNS -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== dns-baseline complete ==="
Write-Host "Role       : DNS Server"
Write-Host "Forwarders : 1.1.1.1, 8.8.8.8 (+ root hints)"
Write-Host "Ports      : 53/TCP + 53/UDP"
$DNS_BASELINE$,
  '["53/DNS"]'::jsonb,
  '{"init-setup"}',
  60,
  true,
  '',
  'baseline'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
