  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'rdp-config',
  'RDP (NLA Off)',
  'Enables RDP on 3389, disables NLA, drops to RDP security layer with low encryption, grants student + svcbackup access. Classic brute-force / PtH target.',
  'Network Services',
  'windows',
  'beginner',
  $RDP_CONFIG$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# --- Enable RDP at the registry level ---
Write-Step "Enabling Remote Desktop (fDenyTSConnections = 0)"
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server" -Name "fDenyTSConnections" -Value 0 -Force
# Disable Network Level Authentication so older clients (and brute-force tools) can connect
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "UserAuthentication" -Value 0 -Force
# Keep RDP security layer low (RDP classic, not TLS-enforced)
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "SecurityLayer" -Value 1 -Force
# Don't force strong encryption
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "MinEncryptionLevel" -Value 1 -Force

# --- Firewall rule ---
Write-Step "Enabling Remote Desktop firewall group"
Enable-NetFirewallRule -DisplayGroup "Remote Desktop" -ErrorAction SilentlyContinue | Out-Null
New-NetFirewallRule -DisplayName "Lab-RDP-3389-Allow" -Direction Inbound -Protocol TCP -LocalPort 3389 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

# --- Allow the student + svcbackup accounts to RDP in ---
Write-Step "Granting RDP access to student + svcbackup"
foreach ($u in @("student","svcbackup")) {
    try { Add-LocalGroupMember -Group "Remote Desktop Users" -Member $u -ErrorAction SilentlyContinue } catch {}
}

# --- Weaken: allow password caching client-side (removes the warning dialog) ---
Write-Step "Disabling 'Always prompt for password' on RDP"
Set-ItemProperty -Path "HKLM:\System\CurrentControlSet\Control\Terminal Server\WinStations\RDP-Tcp" -Name "fPromptForPassword" -Value 0 -Force

# --- Ensure TermService is running and set to automatic ---
Write-Step "Starting Remote Desktop Services"
Set-Service -Name TermService -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name TermService -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== rdp-config complete ==="
Write-Host "Port 3389 : open"
Write-Host "NLA       : disabled (deliberate lab weakness)"
Write-Host "RDP users : student, svcbackup"
$RDP_CONFIG$,
  '["3389/RDP"]'::jsonb,
  '{"init-setup"}',
  15,
  true,
  '',
  'vulnerable'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'winrm-http',
  'WinRM HTTP (Unencrypted + Basic)',
  'Bootstraps PSRemoting with an unencrypted 5985 listener, enables Basic auth + TrustedHosts=*. Exposes WinRM to trivial credential-based RCE.',
  'Network Services',
  'windows',
  'intermediate',
  $WINRM_HTTP$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# --- Enable WinRM service + create HTTP listener ---
Write-Step "Bootstrapping WinRM (Enable-PSRemoting -SkipNetworkProfileCheck)"
Enable-PSRemoting -Force -SkipNetworkProfileCheck -ErrorAction SilentlyContinue | Out-Null

Write-Step "Ensuring HTTP listener exists on 5985"
$listeners = & winrm enumerate winrm/config/Listener 2>$null
if ($LASTEXITCODE -ne 0 -or -not ($listeners -match "Transport = HTTP")) {
    & winrm create winrm/config/Listener?Address=*+Transport=HTTP 2>$null | Out-Null
}

# --- Weaken: allow unencrypted + basic auth (makes CrackMapExec-style auth trivially demonstrable) ---
Write-Step "Enabling unencrypted transport + basic auth (lab weakness)"
& winrm set winrm/config/service '@{AllowUnencrypted="true"}' 2>$null | Out-Null
& winrm set winrm/config/service/auth '@{Basic="true"}'        2>$null | Out-Null
& winrm set winrm/config/client/auth  '@{Basic="true"}'        2>$null | Out-Null
& winrm set winrm/config/client '@{AllowUnencrypted="true"}'   2>$null | Out-Null
& winrm set winrm/config/client '@{TrustedHosts="*"}'          2>$null | Out-Null

# --- Firewall rules ---
Write-Step "Opening 5985/TCP (WinRM HTTP) in firewall"
New-NetFirewallRule -DisplayName "Lab-WinRM-5985-Allow" -Direction Inbound -Protocol TCP -LocalPort 5985 -Action Allow -Profile Any -ErrorAction SilentlyContinue | Out-Null

# --- Make sure WinRM service is automatic + started ---
Set-Service -Name WinRM -StartupType Automatic -ErrorAction SilentlyContinue
Start-Service -Name WinRM -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== winrm-http complete ==="
Write-Host "HTTP listener : 5985/TCP"
Write-Host "Basic auth    : ON"
Write-Host "Unencrypted   : ON"
Write-Host "TrustedHosts  : *"
$WINRM_HTTP$,
