INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'event-log-reduction',
  'Log Retention Minimized',
  'Shrinks Application / Security / System / Setup logs to 1MB each, disables PS script-block + module logging, disables 4688 cmdline auditing, clears existing logs, disables Sysmon if present.',
  'Defense Evasion',
  'windows',
  'intermediate',
  $EVENT_LOG_REDUCTION$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# --- Shrink log file sizes so rotation destroys forensic evidence quickly ---
Write-Step "Shrinking Application/Security/System logs to 1MB each"
foreach ($log in @("Application","Security","System","Setup")) {
    try {
        wevtutil sl $log /ms:1048576 /rt:false /ab:false 2>$null
    } catch {}
}

# --- Disable PowerShell script-block + module logging (evasion) ---
Write-Step "Disabling PowerShell module + script-block logging"
$psLog = "HKLM:\Software\Policies\Microsoft\Windows\PowerShell"
if (-not (Test-Path $psLog))                         { New-Item -Path $psLog -Force | Out-Null }
if (-not (Test-Path "$psLog\ScriptBlockLogging"))    { New-Item -Path "$psLog\ScriptBlockLogging" -Force | Out-Null }
if (-not (Test-Path "$psLog\ModuleLogging"))         { New-Item -Path "$psLog\ModuleLogging"      -Force | Out-Null }
New-ItemProperty -Path "$psLog\ScriptBlockLogging" -Name "EnableScriptBlockLogging"              -PropertyType DWord -Value 0 -Force | Out-Null
New-ItemProperty -Path "$psLog\ScriptBlockLogging" -Name "EnableScriptBlockInvocationLogging"    -PropertyType DWord -Value 0 -Force | Out-Null
New-ItemProperty -Path "$psLog\ModuleLogging"      -Name "EnableModuleLogging"                   -PropertyType DWord -Value 0 -Force | Out-Null

# --- Disable command-line process auditing ---
Write-Step "Disabling 4688 command-line auditing"
$cmdAudit = "HKLM:\Software\Microsoft\Windows\CurrentVersion\Policies\System\Audit"
if (-not (Test-Path $cmdAudit)) { New-Item -Path $cmdAudit -Force | Out-Null }
New-ItemProperty -Path $cmdAudit -Name "ProcessCreationIncludeCmdLine_Enabled" -PropertyType DWord -Value 0 -Force | Out-Null

# --- Clear existing logs so students start with nothing to pivot off of ---
Write-Step "Clearing existing logs (Application/Security/System/Windows PowerShell)"
foreach ($log in @("Application","Security","System","Windows PowerShell")) {
    try { wevtutil cl $log 2>$null } catch {}
}

# --- Disable Sysmon if present (service name may or may not exist) ---
$sysmon = Get-Service -Name "Sysmon*" -ErrorAction SilentlyContinue
if ($sysmon) {
    Write-Step "Disabling Sysmon service"
    foreach ($s in $sysmon) { Stop-Service $s -Force -ErrorAction SilentlyContinue; Set-Service $s -StartupType Disabled -ErrorAction SilentlyContinue }
}

Write-Host ""
Write-Host "=== event-log-reduction complete ==="
Write-Host "Log sizes         : 1MB each (rotation destroys ~30s of activity)"
Write-Host "Script-block log  : disabled"
Write-Host "Module log        : disabled"
Write-Host "4688 cmdline      : disabled"
Write-Host "Existing logs     : cleared"
$EVENT_LOG_REDUCTION$,
  '[]'::jsonb,
  '{"init-setup"}',
  15,
  true,
  '',
  'vulnerable'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

INSERT INTO vuln_scripts (slug, name, description, category, os_target, difficulty, script_content, services_exposed, depends_on, estimated_runtime_sec, is_active, script_args, script_type) VALUES (
  'scheduled-task-privesc',
  'Writable Scheduled Tasks',
  'Two SYSTEM scheduled tasks (LabHealthCheck every 15m, LabDeploy at logon) backed by Users-writable script and .bat files for classic task-hijack privesc; grants Users read on the Tasks folder for enumeration.',
  'Privilege Escalation',
  'windows',
  'intermediate',
  $SCHEDULED_TASK_PRIVESC$$ErrorActionPreference = "Continue"

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "==> $Message"
}

# --- 1. A SYSTEM task whose XML definition is Users-writable ---
Write-Step "Creating SYSTEM task 'LabHealthCheck' with a writable task XML"
$taskFolder = "C:\ProgramData\LabOps"
if (-not (Test-Path $taskFolder)) { New-Item -ItemType Directory -Path $taskFolder -Force | Out-Null }

$healthScript = "$taskFolder\health-check.ps1"
Set-Content $healthScript @'
# Hourly health check - just pings internal services
Test-NetConnection -ComputerName 127.0.0.1 -Port 80 -InformationLevel Quiet | Out-Null
Write-Output "[$(Get-Date)] health check ok"
'@ -Encoding UTF8

# Make the SCRIPT writable by Users - classic privesc: replace contents, wait for next tick
icacls $healthScript /grant "Users:(F)" | Out-Null

$action    = New-ScheduledTaskAction    -Execute "powershell.exe" -Argument "-ExecutionPolicy Bypass -File `"$healthScript`""
$trigger   = New-ScheduledTaskTrigger   -Once -At (Get-Date).AddMinutes(5) -RepetitionInterval (New-TimeSpan -Minutes 15) -RepetitionDuration ([TimeSpan]::MaxValue)
$principal = New-ScheduledTaskPrincipal -UserId "SYSTEM" -LogonType ServiceAccount -RunLevel Highest
$settings  = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries
Register-ScheduledTask -TaskName "LabHealthCheck" -Action $action -Trigger $trigger -Principal $principal -Settings $settings -Force | Out-Null

# --- 2. A Users task that calls into C:\ProgramData\Deploy\deploy.bat (also Users-writable) ---
Write-Step "Creating interactive-user task 'LabDeploy' with Users-writable .bat"
$deployDir = "C:\ProgramData\Deploy"
if (-not (Test-Path $deployDir)) { New-Item -ItemType Directory -Path $deployDir -Force | Out-Null }
Set-Content "$deployDir\deploy.bat" "@echo off`r`necho Deploy stub.`r`nexit /b 0" -Encoding ASCII
icacls "$deployDir"            /grant "Users:(OI)(CI)M" | Out-Null
icacls "$deployDir\deploy.bat" /grant "Users:(F)"       | Out-Null

$dpAction  = New-ScheduledTaskAction -Execute "$deployDir\deploy.bat"
$dpTrigger = New-ScheduledTaskTrigger -AtLogOn
$dpPrinc   = New-ScheduledTaskPrincipal -UserId "SYSTEM" -LogonType ServiceAccount -RunLevel Highest
Register-ScheduledTask -TaskName "LabDeploy" -Action $dpAction -Trigger $dpTrigger -Principal $dpPrinc -Force | Out-Null

# --- 3. Ensure Users can list and read task definitions (so enumeration works) ---
Write-Step "Granting Users read on Tasks folder"
icacls "C:\Windows\System32\Tasks" /grant "Users:(OI)(CI)R" /T 2>$null | Out-Null

Write-Host ""
Write-Host "=== scheduled-task-privesc complete ==="
Write-Host "Task: LabHealthCheck (SYSTEM, every 15m)  -> $healthScript (Users:F)"
Write-Host "Task: LabDeploy      (SYSTEM, at logon)   -> $deployDir\deploy.bat (Users:F)"
$SCHEDULED_TASK_PRIVESC$,
  '[]'::jsonb,
  '{"init-setup"}',
  15,
  true,
  '',
  'vulnerable'
)
ON CONFLICT (slug) DO UPDATE SET
  name                  = EXCLUDED.name,
  description           = EXCLUDED.description,
  category              = EXCLUDED.category,
  difficulty            = EXCLUDED.difficulty,
  script_content        = EXCLUDED.script_content,
  services_exposed      = EXCLUDED.services_exposed,
  depends_on            = EXCLUDED.depends_on,
  estimated_runtime_sec = EXCLUDED.estimated_runtime_sec,
  is_active             = true,
  script_args           = EXCLUDED.script_args,
  script_type           = EXCLUDED.script_type;

COMMIT;
